arrayType:
   type '[' ']'
   ;

functionType:
    '(' ftParameterList? ')' ftReturnType 'throws'?
    ;

ftParameterList:
    ftParameter (',' ftParameter)\* (',' restParameter)?
    | restParameter
    ;

ftParameter:
    identifier ':' type
    ;

restParameter:
    '...' ftParameter
    ;

ftReturnType:
    '=>' type
    ;

